import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Plus, Tag, Trash2 } from 'lucide-react';

const GestionOfertas = () => {
  const { id } = useParams(); // Obtenemos el ID del local de la URL
  const navigate = useNavigate();
  
  // Simulación de ofertas del local
  const [ofertas, setOfertas] = useState([
    { id: 101, producto: "Cerveza Quilmes 1L", precio: "2500", vencimiento: "2024-05-10" }
  ]);

  return (
    <div style={containerStyle}>
      <button onClick={() => navigate('/dashboard')} style={btnVolver}>
        <ArrowLeft size={20} /> Volver al Mapa
      </button>

      <div style={headerStyle}>
        <h2>Gestión de Ofertas - Local #{id}</h2>
        <button style={btnNuevaOferta}><Plus size={20} /> Nueva Oferta</button>
      </div>

      <div style={tablaContenedor}>
        <table style={tablaStyle}>
          <thead>
            <tr style={trStyle}>
              <th>Producto</th>
              <th>Precio</th>
              <th>Vencimiento</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {ofertas.map(o => (
              <tr key={o.id} style={trBodyStyle}>
                <td><Tag size={16} color="#e67e22" /> {o.producto}</td>
                <td>${o.precio}</td>
                <td>{o.vencimiento}</td>
                <td><Trash2 size={18} color="#ef4444" style={{cursor:'pointer'}} /></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

/* --- ESTILOS --- */
const containerStyle = { padding: '40px 5%', background: '#f8fafc', minHeight: '90vh' };
const btnVolver = { display: 'flex', alignItems: 'center', gap: '8px', background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', marginBottom: '20px', fontWeight: '600' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const btnNuevaOferta = { background: '#1e293b', color: 'white', padding: '12px 25px', borderRadius: '12px', border: 'none', display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer', fontWeight: '600' };
const tablaContenedor = { background: 'white', borderRadius: '20px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', overflow: 'hidden' };
const tablaStyle = { width: '100%', borderCollapse: 'collapse', textAlign: 'left' };
const trStyle = { background: '#f1f5f9', color: '#475569', fontSize: '0.9rem' };
const trBodyStyle = { borderBottom: '1px solid #f1f5f9', color: '#1e293b' };

export default GestionOfertas;
